import{c as t,Q as a,j as o,m as r}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"How do I view my current usage?","description":"","frontmatter":{},"headers":[],"relativePath":"guide/recipes/portal/view-usage.md","filePath":"guide/recipes/portal/view-usage.md","lastUpdated":1778912818000}'),s={name:"guide/recipes/portal/view-usage.md"};function i(l,e,n,d,c,u){return a(),o("div",null,[...e[0]||(e[0]=[r('<h1 id="how-do-i-view-my-current-usage" tabindex="-1">How do I view my current usage? <a class="header-anchor" href="#how-do-i-view-my-current-usage" aria-label="Permalink to &quot;How do I view my current usage?&quot;">​</a></h1><div class="tip custom-block"><p class="custom-block-title">Who can do this</p><p><strong>Owner</strong>, <strong>Admin</strong>, or <strong>Billing</strong></p></div><p>The Billing page shows current-period consumption against your plan, with per-meter progress bars so you can spot whether you&#39;re about to go over.</p><h2 id="steps" tabindex="-1">Steps <a class="header-anchor" href="#steps" aria-label="Permalink to &quot;Steps&quot;">​</a></h2><ol><li>Open <strong>Billing</strong> in the sidebar.</li><li>The <strong>Usage</strong> tab is open by default.</li><li>The table shows each meter — Monthly Active Users, API Calls, Storage, Workflows — with current consumption, plan limit, and percentage used.</li></ol><h2 id="result" tabindex="-1">Result <a class="header-anchor" href="#result" aria-label="Permalink to &quot;Result&quot;">​</a></h2><p>Bars at ≥90% are red (action needed), ≥75% yellow (close), and neutral below. Click a row to drill into a per-tenant breakdown for that meter.</p><div class="tip custom-block"><p class="custom-block-title">Set up usage alerts</p><p>Combine this with a <a href="./register-webhook">webhook</a> on <code>usage.threshold_crossed</code> to get notified when a meter crosses 75% / 90% / 100%.</p></div><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./download-invoice">How do I download an invoice?</a></li></ul>',10)])])}const g=t(s,[["render",i]]);export{h as __pageData,g as default};
